args.sparql:
SELECT ?person WHERE {
  ?office rdfs:label "Chief Minister of Tamil Nadu"@en .
  ?person wdt:P39 ?office .
}

SELECT ?person ?personLabel WHERE {
  ?office rdfs:label "Chief Minister of Tamil Nadu"@en .
  ?person wdt:P39 ?office .
  ?person rdfs:label ?personLabel .
  FILTER(LANG(?personLabel) = 'en')
}

